import { describe, expect, it } from 'vitest';

import {
  ActiveAcousticPoseMaster,
  admitAcousticPoseObservation,
  ambientNoPose,
  ambientStanding,
  ambientWalking,
  attentionKeeps,
  attentionScore,
  bandIndex,
  bgm2poseRusticCertificate,
  hardNegative,
  hasHardNegative,
  mixedPoseBin,
  poseResidue,
  sameMusic,
  samePose,
  sourceActive,
  sourceOnlyBin,
  type PoseRecording,
} from '../src/active-acoustic-pose';

describe('frequency support', () => {
  it('bandIndex is stable: low<mid<high', () => {
    expect(bandIndex('low')).toBe(0);
    expect(bandIndex('mid')).toBe(1);
    expect(bandIndex('high')).toBe(2);
  });
});

describe('residue (mirrors source_only_residue_zero / mixed_pose_residue)', () => {
  it('source-only subtraction leaves zero residue', () => {
    for (const music of [0, 1, 5, 42]) {
      expect(poseResidue(sourceOnlyBin('mid', music))).toBe(0);
    }
  });

  it('source-plus-pose subtraction recovers the pose residue exactly', () => {
    for (const [music, pose] of [
      [5, 3],
      [0, 7],
      [12, 1],
    ]) {
      expect(poseResidue(mixedPoseBin('mid', music, pose))).toBe(pose);
    }
  });

  it('residue saturates at zero (Nat truncated subtraction)', () => {
    expect(poseResidue({ band: 'low', musicEnergy: 9, recordedEnergy: 4 })).toBe(
      0,
    );
  });
});

describe('attention gate (mirrors attentionKeeps / attentionScore)', () => {
  it('source-only bins are rejected at positive thresholds', () => {
    // mirrors source_only_not_kept_above_zero / source_only_attention_score_zero
    expect(attentionKeeps(1, sourceOnlyBin('mid', 5))).toBe(false);
    expect(attentionScore(1, sourceOnlyBin('mid', 5))).toBe(0);
  });

  it('source-supported bins with sufficient residue are kept', () => {
    // mirrors mixed_pose_kept / mixed_pose_attention_score
    const bin = mixedPoseBin('mid', 5, 3);
    expect(sourceActive(bin)).toBe(true);
    expect(attentionKeeps(3, bin)).toBe(true);
    expect(attentionScore(1, bin)).toBe(3);
  });

  it('a zero-source bin is never kept even with recorded energy', () => {
    // no source support => carrier inactive => cannot certify pose residue
    const bin = { band: 'high' as const, musicEnergy: 0, recordedEnergy: 9 };
    expect(sourceActive(bin)).toBe(false);
    expect(attentionKeeps(1, bin)).toBe(false);
  });
});

describe('hard negatives (mirrors hardNegative)', () => {
  it('same-music/different-pose is a hard negative', () => {
    expect(sameMusic(ambientStanding, ambientWalking)).toBe(true);
    expect(samePose(ambientStanding, ambientWalking)).toBe(false);
    expect(hardNegative(ambientStanding, ambientWalking)).toBe(true);
  });

  it('different-music is not a hard negative', () => {
    const other: PoseRecording = {
      musicId: 99,
      poseId: 12,
      bin: mixedPoseBin('mid', 5, 4),
    };
    expect(hardNegative(ambientStanding, other)).toBe(false);
  });

  it('hasHardNegative scans an unordered batch', () => {
    expect(hasHardNegative([ambientWalking, ambientStanding])).toBe(true);
    expect(hasHardNegative([ambientStanding])).toBe(false);
  });
});

describe('promotion check: admitAcousticPoseObservation', () => {
  it('admits when residue clears the gate AND a hard negative refutes source identity', () => {
    const a = admitAcousticPoseObservation(
      [ambientStanding, ambientWalking],
      1,
    );
    expect(a.outcome).toBe('claim_admitted');
    expect(a.limitation).toBe('none');
    expect(a.hardNegativeSampled).toBe(true);
    expect(a.keptBins).toEqual([0, 1]);
    expect(a.retainedResidue).toBe(3 + 4);
  });

  it('downgrades to observation_only when no hard negative pins source != pose', () => {
    // one source-supported recording, residue retained, but nothing refutes
    // that source identity is doing the work.
    const a = admitAcousticPoseObservation([ambientStanding], 1);
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('source_identity_unrefuted');
    expect(a.retainedResidue).toBe(3);
  });

  it('withholds when only source-only bins are present', () => {
    const a = admitAcousticPoseObservation([ambientNoPose], 1);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('no_source_supported_residue');
    expect(a.keptBins).toEqual([]);
    expect(a.retainedResidue).toBe(0);
  });

  it('refuses to admit at a non-positive threshold (no inherited source-only rejection)', () => {
    const a = admitAcousticPoseObservation(
      [ambientStanding, ambientWalking],
      0,
    );
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('no_source_supported_residue');
  });
});

describe('ActiveAcousticPoseMaster (mirrors active_acoustic_pose_mesh_witness)', () => {
  it('every boundary witness holds', () => {
    expect(ActiveAcousticPoseMaster.ambientPairIsHardNegative).toBe(true);
    expect(ActiveAcousticPoseMaster.ambientNoPoseRejected).toBe(true);
    expect(ActiveAcousticPoseMaster.ambientStandingResidueKept).toBe(true);
    expect(ActiveAcousticPoseMaster.ambientWalkingResidueKept).toBe(true);
    expect(ActiveAcousticPoseMaster.sourceOnlyRejected).toBe(true);
    expect(ActiveAcousticPoseMaster.poseEchoRetained).toBe(true);
  });

  it('the certificate has all required acoustic gates', () => {
    expect(bgm2poseRusticCertificate).toEqual({
      originalSourceTracked: true,
      residueComputed: true,
      frequencySupportApplied: true,
      hardNegativeSampled: true,
      sourceOnlyRejected: true,
      poseEchoRetained: true,
    });
  });
});
